SELECT rel.resource_id AS resourceId, a.author_id AS authorId, a.name AS name, a.original_name AS originalName, a.country AS country, a.photo_url AS photoUrl, a.description AS description, rel.sort AS sort FROM author a INNER JOIN resource_author_rel rel ON a.author_id = rel.author_id WHERE rel.resource_id IN
#{resourceId}
AND a.deleted = 0 ORDER BY rel.resource_id, rel.sort ASC

SELECT id, author_id AS authorId, name, original_name AS originalName, country, photo_url AS photoUrl, description, source_origin AS sourceOrigin, source_url AS sourceUrl, ctime, mtime, deleted FROM author
deleted = 0
AND (name LIKE CONCAT('%', #{keyword}, '%') OR original_name LIKE CONCAT('%', #{keyword}, '%') OR country LIKE CONCAT('%', #{keyword}, '%'))
AND source_origin = #{sourceOrigin}
ORDER BY ctime DESC
LIMIT #{offset}, #{pageSize}
